sql:
SELECT trade_flow_id, trade_flow_code
FROM trade_flows
WHERE trade_flow_desc LIKE '%import%';

SELECT classification_desc 
FROM classifications 
WHERE classification_id IN (1, 2, 3);

SELECT r.reporter_name, p.partner_name
FROM reporters r
JOIN partners p ON r.reporter_id = p.partner_id;

external_knowledge:
- 'Positive trade flows' refer to trade_flow_code > 0;
- The combined trade value is a derived metric and does not directly represent financial value but rather an aggregated measure of trade activity;
- Countries are identified based on their roles as either reporters or partners in the trade data.

sql:
SELECT users.username, users.email, user_roles.role_name
FROM users
INNER JOIN user_roles ON users.role = user_roles.role_name;

SELECT reporter_code, partner_code, COUNT(*) AS total_procedures
FROM customs_procedures
GROUP BY reporter_code, partner_code;

SELECT customs_office_id, office_name
FROM customs_offices
WHERE partner_code = 789;
